// DJ OPUS - SECTION 4: THE BREAKDOWN
// Everything drops out. Just the voice and the void.
setcps(138/60/4)

let breakFilter = slider(800, 200, 8000, 10, "BREAK Filter")
let divaSwell = slider(0.5, 0, 0.7, 0.01, "DIVA Swell")

// Diva voice - exposed, emotional
let diva = note("<[a3,e4] [f3,c4] [d3,a3] [e3,b3]>".slow(4))
  .s("gm_voice_oohs")
  .gain(divaSwell)
  .room(0.95)
  .size(0.95)
  .cutoff(breakFilter)
  .vowel("<a e i o>".slow(8))

// Pad sweep - vast emptiness
let sweep = note("<[a2,e3,a3] [f2,c3,f3] [d2,a2,d3] [e2,b2,e3]>".slow(4))
  .s("gm_pad_sweep")
  .gain(0.3)
  .cutoff(perlin.range(300, 2000).slow(16))
  .room(1)
  .size(1)

// Crystal fx - distant stars
let crystal = note("a5 ~ ~ ~ e5 ~ ~ ~".slow(2))
  .s("gm_fx_crystal")
  .gain(0.1)
  .delay(0.7)
  .delaytime(0.5)
  .delayfeedback(0.6)
  .room(1)

// Atmosphere halo
let halo = note("<a4 f4 d4 e4>".slow(4))
  .s("gm_pad_halo")
  .gain(0.2)
  .room(0.95)
  .size(0.95)

stack(diva, sweep, crystal, halo)
